<template><div class="page"><h2>声音评价</h2><div class="grid grid-2"><div class="card"><el-form label-position="top"><el-form-item label="声音模型"><el-select class="full" v-model="form.voiceModelId" @change="loadRating"><el-option v-for="v in voices" :key="v.id" :label="v.name" :value="v.id"/></el-select></el-form-item><el-form-item label="评分"><el-rate v-model="form.rating"/></el-form-item><el-form-item label="评价内容"><el-input v-model="form.comment" type="textarea" :rows="6"/></el-form-item><el-button type="primary" @click="submit">提交评价</el-button></el-form><p v-if="rating" class="muted">平均评分：{{rating.avgRating||0}}，评价数：{{rating.count||0}}</p></div><div class="card"><h3>评价历史</h3><div v-for="f in list" :key="f.id" class="history-item"><el-rate :model-value="f.rating" disabled/><p>{{f.comment}}</p><small class="muted">{{f.createdAt}}</small></div><el-empty v-if="!list.length" description="暂无评价"/></div></div></div></template>
<script setup>import { reactive,ref,onMounted } from 'vue';import { ElMessage } from 'element-plus';import { getVoiceList } from '../api/voice';import { getFeedbackList,createFeedback,getVoiceRating } from '../api/feedback';const voices=ref([]),list=ref([]),rating=ref(null);const form=reactive({voiceModelId:null,rating:5,comment:''});async function load(){list.value=await getFeedbackList(form.voiceModelId?{voiceModelId:form.voiceModelId}:undefined).catch(()=>[])||[]}async function loadRating(){rating.value=form.voiceModelId?await getVoiceRating(form.voiceModelId).catch(()=>null):null;load()}async function submit(){if(!form.voiceModelId)return ElMessage.warning('请选择声音模型');await createFeedback(form);ElMessage.success('提交成功');form.comment='';loadRating()}onMounted(async()=>{voices.value=await getVoiceList().catch(()=>[])||[];load()})</script>
